// Transaction Class
class Transaction {
    var senderAddress: String
    var recipientAddress: String
    var amount: Double
    var signature: Data?
    
    init(senderAddress: String, recipientAddress: String, amount: Double) {
        self.senderAddress = senderAddress
        self.recipientAddress = recipientAddress
        self.amount = amount
    }
}

// Blockchain Class (for simplicity, this example uses a local blockchain)
class Blockchain {
    var transactions: [Transaction] = []
    
    func addTransaction(transaction: Transaction) {
        transactions.append(transaction)
    }
    
