        return transactions
    }
}

// Key Generation and Signing
func generateKeyPair() -> (SymmetricKey, SymmetricKey) {
    let keyPair = try! SymmetricKey(size: .kdf).split()
    return keyPair
}

func signTransaction(transaction: Transaction, privateKey: SymmetricKey) -> Data? {
    let hash = try! SHA256.hash(data: transaction.senderAddress.data(using: .utf8)!)
    let signature = try! ECDSA.sign(hash, using: privateKey)
    return signature
}

// Blockchain Communication (for simplicity, this example uses a local blockchain)
func communicateWithBlockchain(transaction: Transaction) {
    let blockchain = Blockchain()
    blockchain.addTransaction(transaction: transaction)
    let blockchainData = try! JSONEncoder().encode(blockchain.transactions)
    print("Blockchain data: \(blockchainData)")
}

